external_knowledge:
- Benign refers to non-cancerous growths;
- Malignant refers to cancerous growths;
- Latest assessment confidence refers to the confidence level of the most recent assessment made for each patient.

sql:
SELECT subtlety_rating, description
FROM subtleties
WHERE subtlety_id = 0;

SELECT abnormality_detected_by, COUNT(abnormality_id) AS num_abnormalities_detected
FROM abnormalities
GROUP BY abnormality_detected_by;
